"use strict";!function(){var btn=document.querySelector(".copy-email-btn");if(btn){var emailLink=document.querySelector('a[href^="mailto:"]');if(emailLink){var email=emailLink.href.replace("mailto:","");btn.addEventListener("click",function(){navigator.clipboard.writeText(email).then(function(){btn.classList.add("copied"),btn.setAttribute("aria-label","Email copied!"),setTimeout(function(){btn.classList.remove("copied"),btn.setAttribute("aria-label","Copy email to clipboard")},2e3)})})}}}(),function(){var $root=document.querySelector("html"),$langToggle=document.querySelector(".lang-toggle"),languages=["en","ru","uk"];$langToggle.addEventListener("click",function(){$root.setAttribute("lang",(currentLanguageIndex=languages.indexOf($root.getAttribute("lang")),languages[currentLanguageIndex+1]||languages[0]));var currentLanguageIndex},!1)}(),function(){var $readingModeToggle=document.querySelector(".reading-mode-toggle");$readingModeToggle.addEventListener("click",function(){var $page=document.querySelector(".page");$page.classList.toggle("light"),$page.classList.toggle("dark");var isDark=$page.classList.contains("dark");$readingModeToggle.setAttribute("aria-pressed",String(isDark))},!1)}();